class AdjacencyList:
 """
 Graph representation using adjacency list.
 Supports both directed and undirected, weighted and unweighted graphs.
 """

 def __init__(self, num_vertices, directed=False, weighted=False):
 """
 Initialize the adjacency list.

 Args:
 num_vertices: Number of vertices in the graph
 directed: True for directed graph, False for undirected
 weighted: True for weighted graph, False otherwise
 """
 self.num_vertices = num_vertices
 self.directed = directed
 self.weighted = weighted

 # Create list of empty lists for each vertex
 self.adj_list = [[] for _ in range(num_vertices)]

 def add_edge(self, u, v, weight=1):
 """
 Add an edge between vertices u and v.

 Args:
 u: Source vertex
 v: Destination vertex
 weight: Weight of the edge (default=1)
 """
 if self.weighted:
 # Store as tuple (neighbor, weight)
 self.adj_list[u].append((v, weight))
 if not self.directed:
 self.adj_list[v].append((u, weight))
 else:
 # Store just the neighbor
 self.adj_list[u].append(v)
 if not self.directed:
 self.adj_list[v].append(u)

 def remove_edge(self, u, v):
 """Remove edge between vertices u and v."""
 if self.weighted:
 self.adj_list[u] = [(n, w) for n, w in self.adj_list[u] if n != v]
 if not self.directed:
 self.adj_list[v] = [(n, w) for n, w in self.adj_list[v] if n != u]
 else:
 self.adj_list[u] = [n for n in self.adj_list[u] if n != v]
 if not self.directed:
 self.adj_list[v] = [n for n in self.adj_list[v] if n != u]

 def has_edge(self, u, v):
 """Check if edge exists between u and v."""
 if self.weighted:
 return any(neighbor == v for neighbor, _ in self.adj_list[u])
 return v in self.adj_list[u]

 def get_edge_weight(self, u, v):
 """Get weight of edge between u and v."""
 if self.weighted:
 for neighbor, weight in self.adj_list[u]:
 if neighbor == v:
 return weight
 return 1 if self.has_edge(u, v) else None

 def get_neighbors(self, v):
 """Get all neighbors of vertex v."""
 if self.weighted:
 return [neighbor for neighbor, _ in self.adj_list[v]]
 return list(self.adj_list[v])

 def get_degree(self, v):
 """Get degree of vertex v (out-degree for directed)."""
 return len(self.adj_list[v])

 def in_degree(self, v):
 """Get in-degree of vertex v (for directed graphs)."""
 if not self.directed:
 return self.get_degree(v)

 indegree = 0
 for i in range(self.num_vertices):
 if self.has_edge(i, v):
 indegree += 1
 return indegree

 def display(self):
 """Print the adjacency list."""
 print("\nAdjacency List:")
 for i in range(self.num_vertices):
 if self.weighted:
 neighbors = [f"({n}, w={w})" for n, w in self.adj_list[i]]
 else:
 neighbors = [str(n) for n in self.adj_list[i]]
 print(f"Vertex {i}: {' -> '.join(neighbors) if neighbors else 'empty'}")

 def bfs(self, start):
 """Breadth-first search starting from vertex start."""
 visited = [False] * self.num_vertices
 queue = [start]
 visited[start] = True
 result = []

 while queue:
 vertex = queue.pop(0)
 result.append(vertex)

 for neighbor in self.get_neighbors(vertex):
 if not visited[neighbor]:
 visited[neighbor] = True
 queue.append(neighbor)

 return result

 def dfs(self, start):
 """Depth-first search starting from vertex start."""
 visited = [False] * self.num_vertices
 result = []

 def dfs_helper(v):
 visited[v] = True
 result.append(v)
 for neighbor in self.get_neighbors(v):
 if not visited[neighbor]:
 dfs_helper(neighbor)

 dfs_helper(start)
 return result


