#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

#define MAX_VERTICES 100
#define INF 99999

typedef struct {
 int num_vertices;
 int directed; // 1 for directed, 0 for undirected
 int weighted; // 1 for weighted, 0 for unweighted
 int matrix[MAX_VERTICES][MAX_VERTICES];
} GraphMatrix;

// Create and initialize graph
GraphMatrix* create_graph(int n, int directed, int weighted) {
 GraphMatrix* g = (GraphMatrix*)malloc(sizeof(GraphMatrix));
 g->num_vertices = n;
 g->directed = directed;
 g->weighted = weighted;

 // Initialize matrix
 for (int i = 0; i < n; i++) {
 for (int j = 0; j < n; j++) {
 if (i == j) {
 g->matrix[i][j] = 0; // No self-loops
 } else if (weighted) {
 g->matrix[i][j] = INF; // No edge
 } else {
 g->matrix[i][j] = 0;
 }
 }
 }
 return g;
}

// Add edge between u and v
void add_edge(GraphMatrix* g, int u, int v, int weight) {
 if (u < 0 || u >= g->num_vertices || v < 0 || v >= g->num_vertices) {
 printf("Error: Invalid vertex index\n");
 return;
 }

 int w = (g->weighted) ? weight : 1;
 g->matrix[u][v] = w;

 // For undirected graph, add reverse edge
 if (!g->directed) {
 g->matrix[v][u] = w;
 }
}

// Remove edge between u and v
void remove_edge(GraphMatrix* g, int u, int v) {
 if (g->weighted) {
 g->matrix[u][v] = INF;
 if (!g->directed) {
 g->matrix[v][u] = INF;
 }
 } else {
 g->matrix[u][v] = 0;
 if (!g->directed) {
 g->matrix[v][u] = 0;
 }
 }
}

// Check if edge exists
bool has_edge(GraphMatrix* g, int u, int v) {
 if (g->weighted) {
 return g->matrix[u][v] != INF;
 }
 return g->matrix[u][v] == 1;
}

// Get weight of edge
int get_weight(GraphMatrix* g, int u, int v) {
 return g->matrix[u][v];
}

// Get all neighbors of vertex v
void get_neighbors(GraphMatrix* g, int v, int* neighbors, int* count) {
 *count = 0;
 for (int i = 0; i < g->num_vertices; i++) {
 if (has_edge(g, v, i)) {
 neighbors[*count] = i;
 (*count)++;
 }
 }
}

// Get degree of vertex
int get_degree(GraphMatrix* g, int v) {
 int degree = 0;
 for (int i = 0; i < g->num_vertices; i++) {
 if (has_edge(g, v, i)) {
 degree++;
 }
 }
 return degree;
}

// Get in-degree (for directed graphs)
int get_in_degree(GraphMatrix* g, int v) {
 if (!g->directed) {
 return get_degree(g, v);
 }

 int indegree = 0;
 for (int i = 0; i < g->num_vertices; i++) {
 if (has_edge(g, i, v)) {
 indegree++;
 }
 }
 return indegree;
}

// Display adjacency matrix
void display(GraphMatrix* g) {
 printf("\nAdjacency Matrix (V=%d):\n", g->num_vertices);
 printf(" ");
 for (int i = 0; i < g->num_vertices; i++) {
 printf("%3d ", i);
 }
 printf("\n");

 for (int i = 0; i < g->num_vertices; i++) {
 printf("%3d: ", i);
 for (int j = 0; j < g->num_vertices; j++) {
 if (g->weighted && g->matrix[i][j] == INF) {
 printf(" INF");
 } else {
 printf("%3d ", g->matrix[i][j]);
 }
 }
 printf("\n");
 }
}

// Check if matrix is symmetric (for undirected graphs)
bool is_symmetric(GraphMatrix* g) {
 if (g->directed) return false;

 for (int i = 0; i < g->num_vertices; i++) {
 for (int j = 0; j < g->num_vertices; j++) {
 if (g->matrix[i][j] != g->matrix[j][i]) {
 return false;
 }
 }
 }
 return true;
}

int main() {
 // Create undirected graph with 4 vertices
 printf("=== Undirected Graph ===");
 GraphMatrix* g = create_graph(4, 0, 0);

 add_edge(g, 0, 1, 1);
 add_edge(g, 0, 2, 1);
 add_edge(g, 1, 2, 1);
 add_edge(g, 1, 3, 1);
 add_edge(g, 2, 3, 1);

 display(g);

 printf("\nIs edge (0,2) present? %s\n", has_edge(g, 0, 2) ? "Yes" : "No");

 int neighbors[10], count;
 get_neighbors(g, 1, neighbors, &count);
 printf("Neighbors of vertex 1: ");
 for (int i = 0; i < count; i++) {
 printf("%d ", neighbors[i]);
 }
 printf("\n");

 printf("Degree of vertex 1: %d\n", get_degree(g, 1));
 printf("Is matrix symmetric? %s\n", is_symmetric(g) ? "Yes" : "No");

 // Create weighted directed graph
 printf("\n=== Weighted Directed Graph ===");
 GraphMatrix* wg = create_graph(4, 1, 1);

 add_edge(wg, 0, 1, 5);
 add_edge(wg, 0, 2, 3);
 add_edge(wg, 1, 2, 2);
 add_edge(wg, 1, 3, 7);
 add_edge(wg, 2, 3, 4);

 display(wg);

 printf("\nWeight of edge (0,1): %d\n", get_weight(wg, 0, 1));
 printf("Out-degree of vertex 1: %d\n", get_degree(wg, 1));
 printf("In-degree of vertex 3: %d\n", get_in_degree(wg, 3));

 // Free memory
 free(g);
 free(wg);

 return 0;
}

import java.util.*;

public class GraphAdjacencyList {
 private int numVertices;
 private boolean directed;
 private boolean weighted;
 private List<List<Edge>> adjList;

 // Inner class to represent a weighted edge
 private static class Edge {
 int destination;
 int weight;

 Edge(int destination) {
 this(destination, 1);
 }

 Edge(int destination, int weight) {
 this.destination = destination;
 this.weight = weight;
 }
 }

 public GraphAdjacencyList(int numVertices, boolean directed, boolean weighted) {
 this.numVertices = numVertices;
 this.directed = directed;
 this.weighted = weighted;

 // Initialize adjacency list
 this.adjList = new ArrayList<>(numVertices);
 for (int i = 0; i < numVertices; i++) {
 this.adjList.add(new ArrayList<>());
 }
 }

 public void addEdge(int u, int v) {
 addEdge(u, v, 1);
 }

 public void addEdge(int u, int v, int weight) {
 if (u < 0 || u >= numVertices || v < 0 || v >= numVertices) {
 throw new IllegalArgumentException("Invalid vertex index");
 }

 // Add edge from u to v
 if (weighted) {
 adjList.get(u).add(new Edge(v, weight));
 } else {
 adjList.get(u).add(new Edge(v));
 }

 // For undirected graph, add reverse edge
 if (!directed) {
 if (weighted) {
 adjList.get(v).add(new Edge(u, weight));
 } else {
 adjList.get(v).add(new Edge(u));
 }
 }
 }

 public void removeEdge(int u, int v) {
 List<Edge> listU = adjList.get(u);
 listU.removeIf(edge -> edge.destination == v);

 if (!directed) {
 List<Edge> listV = adjList.get(v);
 listV.removeIf(edge -> edge.destination == u);
 }
 }

 public boolean hasEdge(int u, int v) {
 for (Edge edge : adjList.get(u)) {
 if (edge.destination == v) {
 return true;
 }
 }
 return false;
 }

 public int getWeight(int u, int v) {
 for (Edge edge : adjList.get(u)) {
 if (edge.destination == v) {
 return edge.weight;
 }
 }
 return -1; // No edge exists
 }

 public List<Integer> getNeighbors(int v) {
 List<Integer> neighbors = new ArrayList<>();
 for (Edge edge : adjList.get(v)) {
 neighbors.add(edge.destination);
 }
 return neighbors;
 }

 public int getDegree(int v) {
 return adjList.get(v).size();
 }

 public int getInDegree(int v) {
 if (!directed) {
 return getDegree(v);
 }

 int inDegree = 0;
 for (int i = 0; i < numVertices; i++) {
 if (hasEdge(i, v)) {
 inDegree++;
 }
 }
 return inDegree;
 }

 public void display() {
 System.out.println("\nAdjacency List:");
 for (int i = 0; i < numVertices; i++) {
 System.out.print("Vertex " + i + ": ");
 List<Edge> edges = adjList.get(i);
 if (edges.isEmpty()) {
 System.out.println("empty");
 } else {
 for (int j = 0; j < edges.size(); j++) {
 Edge e = edges.get(j);
 if (weighted) {
 System.out.print("-> (" + e.destination + ", w=" + e.weight + ")");
 } else {
 System.out.print("-> " + e.destination);
 }
 }
 System.out.println();
 }
 }
 }

 // Breadth-First Search
 public List<Integer> bfs(int start) {
 List<Integer> result = new ArrayList<>();
 boolean[] visited = new boolean[numVertices];
 Queue<Integer> queue = new LinkedList<>();

 visited[start] = true;
 queue.offer(start);

 while (!queue.isEmpty()) {
 int vertex = queue.poll();
 result.add(vertex);

 for (Edge edge : adjList.get(vertex)) {
 if (!visited[edge.destination]) {
 visited[edge.destination] = true;
 queue.offer(edge.destination);
 }
 }
 }
 return result;
 }

 // Depth-First Search
 public List<Integer> dfs(int start) {
 List<Integer> result = new ArrayList<>();
 boolean[] visited = new boolean[numVertices];
 dfsHelper(start, visited, result);
 return result;
 }

 private void dfsHelper(int vertex, boolean[] visited, List<Integer> result) {
 visited[vertex] = true;
 result.add(vertex);

 for (Edge edge : adjList.get(vertex)) {
 if (!visited[edge.destination]) {
 dfsHelper(edge.destination, visited, result);
 }
 }
 }

 public static void main(String[] args) {
 // Create undirected graph with 4 vertices
 System.out.println("=== Undirected Graph ===");
 GraphAdjacencyList g = new GraphAdjacencyList(4, false, false);

 g.addEdge(0, 1);
 g.addEdge(0, 2);
 g.addEdge(1, 2);
 g.addEdge(1, 3);
 g.addEdge(2, 3);

 g.display();

 System.out.println("\nIs edge (0,2) present? " + g.hasEdge(0, 2));
 System.out.println("Neighbors of vertex 1: " + g.getNeighbors(1));
 System.out.println("Degree of vertex 1: " + g.getDegree(1));

 // Create weighted directed graph
 System.out.println("\n=== Weighted Directed Graph ===");
 GraphAdjacencyList wg = new GraphAdjacencyList(4, true, true);

 wg.addEdge(0, 1, 5);
 wg.addEdge(0, 2, 3);
 wg.addEdge(1, 2, 2);
 wg.addEdge(1, 3, 7);
 wg.addEdge(2, 3, 4);

 wg.display();

 System.out.println("\nWeight of edge (0,1): " + wg.getWeight(0, 1));
 System.out.println("Out-degree of vertex 1: " + wg.getDegree(1));
 System.out.println("In-degree of vertex 3: " + wg.getInDegree(3));

 // Demonstrate traversal
 System.out.println("\n=== Graph Traversal ===");
 System.out.println("BFS from vertex 0: " + g.bfs(0));
 System.out.println("DFS from vertex 0: " + g.dfs(0));
 }
}
